const pdfParse = require('pdf-parse');
const mammoth = require('mammoth');
const XLSX = require('xlsx');

const body = $json.body ?? $json;
const binaries = $binary || {};

if (!Object.keys(binaries).length) {
  throw new Error('Nu au fost primite fisiere.');
}

function normalizeText(value) {
  return String(value || '')
    .replace(/\r/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

async function extractByType(binaryKey, file) {
  const name = file.fileName || 'fisier-fara-nume';
  const ext = name.includes('.') ? name.split('.').pop().toLowerCase() : '';
  const mime = (file.mimeType || '').toLowerCase();
  const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);

  if (ext === 'txt' || ext === 'md' || mime.includes('text/plain')) {
    return buffer.toString('utf8');
  }

  if (ext === 'pdf' || mime.includes('pdf')) {
    const data = await pdfParse(buffer);
    return data.text || '';
  }

  if (ext === 'docx' || mime.includes('wordprocessingml')) {
    const out = await mammoth.extractRawText({ buffer });
    return out.value || '';
  }

  if (ext === 'doc' || mime.includes('msword')) {
    return buffer.toString('utf8');
  }

  if (ext === 'xlsx' || ext === 'xls' || ext === 'csv' || mime.includes('sheet') || mime.includes('csv')) {
    const wb = XLSX.read(buffer, { type: 'buffer' });
    const sheets = wb.SheetNames.map((sheetName) => {
      const ws = wb.Sheets[sheetName];
      const csv = XLSX.utils.sheet_to_csv(ws);
      return '# Sheet: ' + sheetName + '\n' + csv;
    });
    return sheets.join('\n\n');
  }

  return buffer.toString('utf8');
}

const docs = [];
for (const [binaryKey, file] of Object.entries(binaries)) {
  const extracted = await extractByType.call(this, binaryKey, file);
  const cleaned = normalizeText(extracted);

  docs.push({
    binaryKey,
    fileName: file.fileName || binaryKey,
    mimeType: file.mimeType || 'unknown',
    chars: cleaned.length,
    text: cleaned.slice(0, 4000),
  });
}

const combinedText = docs
  .map((doc, idx) => '## Document ' + (idx + 1) + ': ' + doc.fileName + '\n' + doc.text)
  .join('\n\n---\n\n')
  .slice(0, 12000);

const settings = {
  tone: body.tone || 'profesionist',
  language: body.language || 'romana',
  audience: body.audience || 'public general',
  platforms: body.platforms || 'Instagram, Facebook',
  model: body.model || 'qwen2.5:7b',
};

const prompt = [
  'Esti un social media strategist senior. Primesti idei brute din documente si le transformi in continut gata de publicare.',
  'Raspunzi EXCLUSIV JSON valid, fara markdown, fara explicatii in afara JSON-ului.',
  '',
  'Creeaza rezultat in limba ' + settings.language + ', ton ' + settings.tone + ', public tinta ' + settings.audience + ', platforme ' + settings.platforms + '.',
  '',
  'Reguli obligatorii lungime caption:',
  '- Instagram max 2200',
  '- Facebook max 63206',
  '- LinkedIn max 3000',
  '- TikTok max 2200',
  '- X max 280',
  '',
  'Cerinta variatii:',
  '- Pentru FIECARE platforma inclusa, genereaza EXACT 2 variante: variantA si variantB.',
  '',
  'Text extras din documente:',
  combinedText,
  '',
  'Schema JSON OBLIGATORIE:',
  '{',
  '  "summary": "rezumat strategic 2-4 fraze",',
  '  "posts": [',
  '    {',
  '      "platform": "Instagram",',
  '      "variantA": {',
  '        "caption": "text complet postare",',
  '        "hashtags": ["#tag1", "#tag2"],',
  '        "cta": "apel la actiune",',
  '        "visualIdea": "idee vizuala"',
  '      },',
  '      "variantB": {',
  '        "caption": "text complet postare alternativa",',
  '        "hashtags": ["#tag1", "#tag2"],',
  '        "cta": "apel la actiune alternativa",',
  '        "visualIdea": "idee vizuala alternativa"',
  '      }',
  '    }',
  '  ],',
  '  "calendar": [',
  '    {',
  '      "day": "Luni",',
  '      "time": "18:00",',
  '      "platform": "Instagram",',
  '      "topic": "tema"',
  '    }',
  '  ]',
  '}',
].join('\n');

return [{
  json: {
    settings,
    documents: docs.map((d) => ({
      fileName: d.fileName,
      mimeType: d.mimeType,
      chars: d.chars,
    })),
    combinedText,
    prompt,
  },
}];

const source = $items('Extract Document Text', 0, 0)[0].json;
const data = $json;

const PLATFORM_LIMITS = {
  Instagram: 2200,
  Facebook: 63206,
  LinkedIn: 3000,
  TikTok: 2200,
  X: 280,
};

function asArray(input) {
  return Array.isArray(input) ? input : [];
}

function cleanText(value) {
  return String(value || '').replace(/\s+/g, ' ').trim();
}

function clampCaption(platform, caption) {
  const max = PLATFORM_LIMITS[platform] || 2200;
  const normalized = cleanText(caption);
  if (normalized.length <= max) return normalized;
  return normalized.slice(0, Math.max(0, max - 3)).trim() + '...';
}

function normalizeVariant(platform, variant) {
  const value = variant || {};
  return {
    caption: clampCaption(platform, value.caption),
    hashtags: asArray(value.hashtags).map((tag) => cleanText(tag)).filter(Boolean),
    cta: cleanText(value.cta),
    visualIdea: cleanText(value.visualIdea),
  };
}

function buildPlainTextExport(formatted, settings) {
  const lines = [];
  lines.push('=== SOCIAL MEDIA READY COPY ===');
  lines.push('Ton: ' + settings.tone);
  lines.push('Limba: ' + settings.language);
  lines.push('Audienta: ' + settings.audience);
  lines.push('Platforme: ' + settings.platforms);
  lines.push('Model: ' + settings.model);
  lines.push('');

  if (formatted.summary) {
    lines.push('REZUMAT STRATEGIC');
    lines.push(formatted.summary);
    lines.push('');
  }

  for (const post of asArray(formatted.posts)) {
    lines.push('PLATFORMA: ' + (post.platform || 'General'));
    lines.push('Limita caption: ' + (PLATFORM_LIMITS[post.platform] || 2200));
    lines.push('');

    lines.push('Varianta A');
    lines.push(post.variantA?.caption || '');
    lines.push('Hashtags: ' + (post.variantA?.hashtags || []).join(' '));
    lines.push('CTA: ' + (post.variantA?.cta || ''));
    lines.push('Vizual: ' + (post.variantA?.visualIdea || ''));
    lines.push('');

    lines.push('Varianta B');
    lines.push(post.variantB?.caption || '');
    lines.push('Hashtags: ' + (post.variantB?.hashtags || []).join(' '));
    lines.push('CTA: ' + (post.variantB?.cta || ''));
    lines.push('Vizual: ' + (post.variantB?.visualIdea || ''));
    lines.push('');
    lines.push('----------------------------------------');
    lines.push('');
  }

  if (asArray(formatted.calendar).length) {
    lines.push('CALENDAR PROPUS');
    for (const item of formatted.calendar) {
      lines.push('- ' + (item.day || 'Zi') + ' ' + (item.time || '') + ' | ' + (item.platform || 'Platforma') + ' | ' + (item.topic || 'Tema'));
    }
  }

  return lines.join('\n').trim();
}

if (data.error) {
  throw new Error('Ollama error: ' + data.error);
}

let rawText = '';
if (typeof data.response === 'string' && data.response.trim()) {
  rawText = data.response.trim();
}

if (!rawText && typeof data.output_text === 'string' && data.output_text.trim()) {
  rawText = data.output_text.trim();
}

if (!rawText) {
  throw new Error('Modelul AI nu a returnat continut text. Verifica modelul Ollama.');
}

let formatted = null;
const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/, '')
  .trim();

try {
  formatted = JSON.parse(cleaned);
} catch (error) {
  formatted = null;
}

if (!formatted || !Array.isArray(formatted.posts)) {
  const platforms = String(source.settings.platforms || 'Instagram, Facebook')
    .split(',')
    .map((item) => cleanText(item))
    .filter(Boolean);

  const seed = cleanText(rawText).slice(0, 1000) || 'Idee de postare social media';

  formatted = {
    summary: cleanText(rawText).slice(0, 350),
    posts: platforms.map((platform) => ({
      platform,
      variantA: {
        caption: clampCaption(platform, seed + ' (varianta A)'),
        hashtags: ['#socialmedia', '#marketing'],
        cta: 'Scrie-ne pentru detalii.',
        visualIdea: 'Cadru simplu cu mesaj principal si branding.',
      },
      variantB: {
        caption: clampCaption(platform, seed + ' (varianta B)'),
        hashtags: ['#content', '#business'],
        cta: 'Comenteaza daca vrei varianta personalizata.',
        visualIdea: 'Carousel cu beneficii cheie.',
      },
    })),
    calendar: [],
  };
}

formatted.posts = formatted.posts.map((post) => {
  const platform = cleanText(post.platform) || 'Instagram';
  return {
    platform,
    variantA: normalizeVariant(platform, post.variantA),
    variantB: normalizeVariant(platform, post.variantB),
  };
});

const plainText = buildPlainTextExport(formatted, source.settings);

return [{
  json: {
    status: 'ok',
    source: {
      files: source.documents,
      settings: source.settings,
    },
    formatted,
    exports: {
      plainText,
    },
    rawText,
  },
}];
